async function c(i=1){const o=`${window.APP_CONFIG?.baseUrl||"/"}api/regions?country_id=${i}`;try{const t=await(await fetch(o)).json();return t.success?t.data.map(n=>({id:n.id,name:n.region})):[]}catch(e){return console.error("Fetch Regions Error:",e),[]}}function s(i){const r=document.getElementById(i);if(!r)return;const o=r.querySelector('select[name="countryId"]'),e=r.querySelector('select[name="regionId"]');!o||!e||o.addEventListener("change",async()=>{const t=parseInt(o.value);e.innerHTML='<option value="">Loading...</option>',e.disabled=!0;try{const n=await c(t);e.innerHTML=`
                <option value="">Select Region</option>
                ${n.map(a=>`<option value="${a.id}">${a.name}</option>`).join("")}
            `}catch(n){console.error("Failed to reload regions:",n),e.innerHTML='<option value="">Error loading regions</option>'}finally{e.disabled=!1}})}export{s as e,c as f};
